const output = $input.first().json.stdout || '';
const lines = output.split('\n');
// Find the JSON result block (last {...} block in output)
let jsonStr = '';
let braceDepth = 0;
let capturing = false;
for (const line of lines) {
  for (const ch of line) {
    if (ch === '{') { braceDepth++; capturing = true; }
    if (capturing) jsonStr += ch;
    if (ch === '}') braceDepth--;
    if (capturing && braceDepth === 0) break;
  }
  if (capturing) jsonStr += '\n';
  if (capturing && braceDepth === 0) break;
}
try {
  const result = JSON.parse(jsonStr);
  return [{ json: result }];
} catch(e) {
  return [{ json: { success: false, error: 'Failed to parse pipeline output', raw: output } }];
}

const result = $input.first().json;
const product = result.product || {};
const lines = [
  `✅ *ReviewPocketShorts posted!*`,
  ``,
  `📦 *${product.title || 'Product'}*`,
  `💰 ${product.price || ''}  ⭐ ${product.rating || ''}/5`,
  ``,
  `🎬 YouTube: ${result.youtube_url || 'N/A'}`,
  `📸 Instagram: ${result.instagram_permalink || 'N/A'}`,
  ``,
  `🛒 Affiliate: ${product.affiliate_url || 'N/A'}`,
];
return [{ json: { message: lines.join('\n') } }];

